mapper.select:
SELECT e.*
FROM sys_flow_entry e

    e.deleted = 0

        AND e.entry_name LIKE CONCAT('%', #{query.entryName}, '%')


        AND e.entry_code = #{query.entryCode}


        AND e.model_key = #{query.modelKey}


        AND e.form_key = #{query.formKey}


        AND e.data_mode = #{query.dataMode}


        AND e.status = #{query.status}


ORDER BY e.sort ASC, e.create_time DESC

SELECT COUNT(1)
FROM sys_flow_entry e
WHERE e.deleted = 0
  AND e.entry_code = #{entryCode}

    AND e.id != #{excludeId}
